def compute_score() -> tuple[str, float]:
    # Use python-pptx to check slide 18 title text in modified PPT
    from pptx import Presentation
    import re
    PR = Presentation(modified_ppt_path)
    orig_PR = Presentation(original_ppt_path)
    slide_idx = 17 # 0-based
    if slide_idx >= len(PR.slides):
        return ("Slide 18 does not exist in modified presentation.", 0.0)
    slide = PR.slides[slide_idx]
    # Try to find any shape containing the words "Myopia" and "Nearsightedness"
    title_text = None
    for shape in slide.shapes:
        if shape.has_text_frame and shape.text_frame.text:
            text = shape.text_frame.text.strip()
            if "myopia" in text.lower() and "nearsightedness" in text.lower():
                title_text = text
                break

    if not title_text:
        return ("Could not find a heading on slide 18 in modified presentation.", 0.0)
    # Check for exact required heading
    required_heading = "Nearsightedness (Myopia)"
    if title_text == required_heading:
        return ("Heading correctly changed to 'Nearsightedness (Myopia)'.", 1.0)
    elif title_text.lower().strip() == required_heading.lower():
        return ("Heading text matches ignoring case.", 0.9)
    elif re.sub(r'\s+', '', title_text.lower()) == re.sub(r'\s+', '', required_heading.lower()):
        return ("Heading matches with minor whitespace errors.", 0.8)
    elif "myopia" in title_text.lower() and "nearsightedness" in title_text.lower():
        return ("Heading contains both 'Nearsightedness' and 'Myopia' but formatting is off.", 0.7)
    elif "myopia" in title_text.lower():
        return ("Heading still says just 'Myopia'.", 0.0)
    else:
        return (f"Heading on slide 18 is incorrect: '{title_text}'", 0.0)

def compute_score() -> tuple[str, float]:
    # Use ppt_diff to look for modifications to slide 18 other than heading
    # We'll compare original and modified slide objects for slide 18
    orig_slide = None
    mod_slide = None
    for slide in ppt_diff.modified_slides:
        s1, s2 = slide
        if s1.slide_number == 18 or s2.slide_number == 18:
            orig_slide = s1
            mod_slide = s2
            break
    if orig_slide is None and mod_slide is None:
        # If slide wasn't modified at all, that's OK
        return ("No other modifications detected on slide 18.", 1.0)
    # Compare notes, layout_type, and element_count
    if orig_slide and mod_slide:
        diffs = []
        if (orig_slide.layout_type != mod_slide.layout_type):
            diffs.append("Layout type changed.")
        if (orig_slide.notes or '').strip() != (mod_slide.notes or '').strip():
            diffs.append("Slide notes changed.")
        if abs(orig_slide.element_count - mod_slide.element_count) > 1:
            # Allowing for heading split or merge
            diffs.append(f"Element count changed from {orig_slide.element_count} to {mod_slide.element_count}.")
        if not diffs:
            return ("Only heading changed on slide 18.", 1.0)
        return ("Some extraneous changes on slide 18: " + ", ".join(diffs), 0.6)
    return ("Unable to compare slides for extraneous changes.", 0.7)

def compute_score() -> tuple[str, float]:
    # Check ppt_diff for changes to slides other than 18
    changed_slides = set()
    for slide in ppt_diff.added_slides + ppt_diff.removed_slides:
        changed_slides.add(slide.slide_number)
    for s1, s2 in ppt_diff.modified_slides:
        if s1.slide_number != 18:
            changed_slides.add(s1.slide_number)
    changed_slides = {n for n in changed_slides if n != 18}
    if not changed_slides:
        return ("No slides other than 18 were changed.", 1.0)
    else:
        return (f"Slides changed other than 18: {sorted(list(changed_slides))}", 0.0)
